// ─── Letter template helpers ──────────────────────────────────────────────────

function makeLetterChecklist(id: string, title: string, description: string, html: string): Checklist {
  return {
    id,
    title,
    description,
    objective: '',
    sections: [
      {
        id: `${id}-section`,
        title,
        isExpanded: true,
        questions: [
          {
            id: `${id}-body`,
            text: html,
            answerType: 'none',
            options: [],
            required: false,
            answer: '',
          } as Question,
        ],
      },
    ],
    createdAt: new Date(),
    updatedAt: new Date(),
  };
}

